INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_002_001", 2, 1, "訓練はまだ\nここからですわ", 3000, "調子が上がって\nきたなっ", 1000, 2, 2, "vo_minigame_1013_icon_1_002_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_003_001", 2, 2, "クスクス、悪くない\n流れですわね", 3000, "ほらほら、\nまだいけるだろ？", 5000, 2, 2, "vo_minigame_1013_icon_1_003_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_004_001", 3, 3, "すばらしい\n記録ですわ", 3000, "へへっ、おまえら\nやるじゃねえか！", 10000, 2, 2, "vo_minigame_1013_icon_1_004_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_005_001", 3, 4, "乗りに乗って\nいますわね", 3000, "あたしたちはまだ\n止まらねえぜ！", 10000, 3, 2, "vo_minigame_1013_icon_1_005_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_005_002", 3, 5, "まだまだ行きます\nついてきなさい", 3000, "見てろよ！\nマコト班の快進撃だ！", 10000, 3, 2, "vo_minigame_1013_icon_1_005_002");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_005_003", 3, 6, "エリコ班の\n本領発揮ですわ！", 3000, "うおぉぉっ！\n絶好調だぜ！", 10000, 3, 2, "vo_minigame_1013_icon_1_005_003");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_006_001", 3, 7, "ここからは\n前人未到の領域です！", 3000, "どこまで行けるか\n楽しみだなっ！", 0, 4, 2, "vo_minigame_1013_icon_1_006_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_007_001", 4, 8, "厄介でしたわ…", 1000, "まだ諦めんなよっ", 1, 5, 3, "vo_minigame_1013_icon_1_007_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_007_002", 4, 9, "油断大敵です", 1000, "冷やっとしたぜ…！", 1, 5, 3, "vo_minigame_1013_icon_1_007_002");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_007_003", 4, 10, "忌々しいっ…", 1000, "弱音を吐くなっ", 1, 5, 3, "vo_minigame_1013_icon_1_007_003");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_008_001", 3, 11, "大所帯ですわね", 1500, "マコト班集合！", 99, 6, 4, "vo_minigame_1013_icon_1_008_001");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_008_002", 3, 12, "エリコ班へようこそ", 1500, "連携してくぞ！", 99, 6, 4, "vo_minigame_1013_icon_1_008_002");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES ("vo_minigame_1013_icon_2_020_001", 6, 13, "ナナカちゃんに\nお任せあれ", 3000, "みんなに力を！", 0, 8, 1, "vo_minigame_1013_icon_1_020_001");
